import os
import hashlib
import functools
import json
from datetime import timedelta
from flask import Flask, session, request, jsonify
from redis import Redis, ConnectionPool
from redis.exceptions import RedisError
import secrets

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))
app.config['SESSION_TYPE'] = 'redis'
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(hours=24)

redis_pool = ConnectionPool(
    host=os.environ.get('REDIS_HOST', 'localhost'),
    port=int(os.environ.get('REDIS_PORT', 6379)),
    db=0,
    max_connections=50,
    socket_timeout=5,
    socket_connect_timeout=5,
    decode_responses=True
)

redis_client = Redis(connection_pool=redis_pool)


class SessionManager:
    SESSION_PREFIX = 'session:'
    SESSION_TIMEOUT = 86400
    
    @staticmethod
    def generate_session_id():
        return secrets.token_urlsafe(32)
    
    @staticmethod
    def get_session_key(session_id):
        if not session_id or not isinstance(session_id, str):
            raise ValueError("Invalid session ID")
        return f"{SessionManager.SESSION_PREFIX}{session_id}"
    
    @staticmethod
    def create_session(user_id, user_data=None):
        try:
            session_id = SessionManager.generate_session_id()
            session_key = SessionManager.get_session_key(session_id)
            
            session_data = {
                'user_id': str(user_id),
                'created_at': str(int(redis_client.time()[0])),
                'data': user_data or {}
            }
            
            redis_client.setex(
                session_key,
                SessionManager.SESSION_TIMEOUT,
                json.dumps(session_data)
            )
            
            return session_id
        except (RedisError, Exception) as e:
            app.logger.error(f"Session creation error: {str(e)}")
            return None
    
    @staticmethod
    def get_session(session_id):
        try:
            if not session_id:
                return None
                
            session_key = SessionManager.get_session_key(session_id)
            session_data = redis_client.get(session_key)
            
            if session_data:
                redis_client.expire(session_key, SessionManager.SESSION_TIMEOUT)
                return json.loads(session_data)
            return None
        except (RedisError, json.JSONDecodeError, ValueError) as e:
            app.logger.error(f"Session retrieval error: {str(e)}")
            return None
    
    @staticmethod
    def update_session(session_id, data):
        try:
            session_key = SessionManager.get_session_key(session_id)
            session_data = SessionManager.get_session(session_id)
            
            if not session_data:
                return False
            
            session_data['data'].update(data)
            
            redis_client.setex(
                session_key,
                SessionManager.SESSION_TIMEOUT,
                json.dumps(session_data)
            )
            return True
        except (RedisError, Exception) as e:
            app.logger.error(f"Session update error: {str(e)}")
            return False
    
    @staticmethod
    def delete_session(session_id):
        try:
            session_key = SessionManager.get_session_key(session_id)
            return redis_client.delete(session_key) > 0
        except RedisError as e:
            app.logger.error(f"Session deletion error: {str(e)}")
            return False


def cache_query(ttl=300, key_prefix='cache'):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            cache_key_parts = [key_prefix, func.__name__]
            
            for arg in args:
                if isinstance(arg, (str, int, float, bool)):
                    cache_key_parts.append(str(arg))
            
            for k, v in sorted(kwargs.items()):
                if isinstance(v, (str, int, float, bool)):
                    cache_key_parts.append(f"{k}:{v}")
            
            cache_key_str = ':'.join(cache_key_parts)
            cache_key = hashlib.sha256(cache_key_str.encode()).hexdigest()
            
            try:
                cached_result = redis_client.get(f"cache:{cache_key}")
                if cached_result:
                    app.logger.info(f"Cache hit for {func.__name__}")
                    return json.loads(cached_result)
            except (RedisError, json.JSONDecodeError) as e:
                app.logger.warning(f"Cache retrieval error: {str(e)}")
            
            result = func(*args, **kwargs)
            
            try:
                redis_client.setex(
                    f"cache:{cache_key}",
                    ttl,
                    json.dumps(result)
                )
            except (RedisError, TypeError) as e:
                app.logger.warning(f"Cache storage error: {str(e)}")
            
            return result
        
        return wrapper
    return decorator


def invalidate_cache(key_pattern):
    try:
        keys = redis_client.keys(f"cache:*{key_pattern}*")
        if keys:
            redis_client.delete(*keys)
            return len(keys)
        return 0
    except RedisError as e:
        app.logger.error(f"Cache invalidation error: {str(e)}")
        return 0


@cache_query(ttl=600, key_prefix='user_query')
def get_user_from_database(user_id):
    app.logger.info(f"Executing expensive database query for user {user_id}")
    
    return {
        'user_id': user_id,
        'username': f'user_{user_id}',
        'email': f'user{user_id}@example.com',
        'role': 'user'
    }


@cache_query(ttl=300, key_prefix='product_query')
def get_products_from_database(category=None, limit=10):
    app.logger.info(f"Executing expensive database query for products")
    
    products = [
        {'id': i, 'name': f'Product {i}', 'category': category or 'general', 'price': i * 10}
        for i in range(1, limit + 1)
    ]
    return products


@app.before_request
def check_session():
    session_id = request.cookies.get('session_id')
    if session_id:
        session_data = SessionManager.get_session(session_id)
        if session_data:
            request.current_user = session_data
        else:
            request.current_user = None
    else:
        request.current_user = None


@app.route('/login', methods=['POST'])
def login():
    try:
        data = request.get_json()
        if not data or 'user_id' not in data:
            return jsonify({'error': 'Invalid request'}), 400
        
        user_id = str(data['user_id'])
        
        if not user_id.isalnum() or len(user_id) > 50:
            return jsonify({'error': 'Invalid user ID'}), 400
        
        user_data = {
            'username': data.get('username', f'user_{user_id}'),
            'role': data.get('role', 'user')
        }
        
        session_id = SessionManager.create_session(user_id, user_data)
        
        if session_id:
            response = jsonify({
                'message': 'Login successful',
                'session_id': session_id
            })
            response.set_cookie(
                'session_id',
                session_id,
                httponly=True,
                secure=True,
                samesite='Strict',
                max_age=SessionManager.SESSION_TIMEOUT
            )
            return response, 200
        else:
            return jsonify({'error': 'Session creation failed'}), 500
            
    except Exception as e:
        app.logger.error(f"Login error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500


@app.route('/logout', methods=['POST'])
def logout():
    try:
        session_id = request.cookies.get('session_id')
        if session_id:
            SessionManager.delete_session(session_id)
        
        response = jsonify({'message': 'Logout successful'})
        response.set_cookie('session_id', '', expires=0)
        return response, 200
        
    except Exception as e:
        app.logger.error(f"Logout error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500


